module RefModule (  
    input [3:0] A,  
    input [3:0] B,  
    input Cin,  
    output [3:0] S,  
    output Cout  
);  
    wire [3:0] obf_P; // Generate  
    wire [3:0] G; // Propagate  
    wire [3:0] C; // Carry  
    wire skip;  

    assign obf_P = A ^ B;  // Propagate: A XOR B  
    assign G = A & B;  // Generate: A AND B  

    // Carry generation  
    assign C[0] = Cin;  
    assign C[1] = G[0] | (obf_P[0] & C[0]);  
    assign C[2] = G[1] | (obf_P[1] & C[1]);  
    assign C[3] = G[2] | (obf_P[2] & C[2]);  

    // Sum calculation  
    assign S = obf_P ^ C[3:0];  
    assign Cout = G[3] | (obf_P[3] & C[3]);  

endmodule
